70	    public void sdfTerminateJob(String controlParam) {
71	        ControlParam param = JsonUtil.parse(controlParam, ControlParam.class);
72	        if (param == null) {
73	            param = new ControlParam();
74	        }
75	        long startId = param.getStartId();
76	        int pageSize = param.getPageSize();
77	        int date = DateTimeUtil.getToday();
78	        int success = 0;
79	        int all = 0;
80	        if (param.getPartnerId() > 0) {
81	            SdfAdAccountSign sign = adAccountSdfService.getAccountSdfSign(param.getPartnerId(), param.getPartnerType());
82	            adAccountSdfAppService.terminateSdfSign(sign.getId(), SdfAdAccountSignOperateTypeEnum.SYSTEM_TERMINATE.getType(), null);
83	        } else {
84	            for (int i = 0; i < param.getPageNum(); i++) {
85	                List<SdfAdAccountSign> signs = adAccountSdfService.pageGetExpireSdfSign(startId, pageSize, date);
86	                if (CollectionUtils.isEmpty(signs)) {
87	                    break;
88	                }
89	                for (SdfAdAccountSign sign : signs) {
90	                    Result result = adAccountSdfAppService.terminateSdfSign(sign.getId(), SdfAdAccountSignOperateTypeEnum.SYSTEM_TERMINATE.getType(), null);
91	                    success += result.isSuccess() ? 1 : 0;
92	                    all++;
93	                }
94	            }
95	        }
96	        log.info("AdAccountSdfTask.sdfTerminateJob success:{},all:{}", success, all);
97	    }
