813	            }
814	
815	            RuleOperateInfo operateInfo = new RuleOperateInfo();
816	            BeanUtils.copyProperties(extraInfo, operateInfo);
817	            operateInfo.setOperateType(operateType);
818	            WmAdGmvToAdRule rule = wmKaGmvToAdDomainService.getRuleByRuleId(ruleId);
819	            if (rule == null) {
820	                return true;
821	            }
822	
823	            int ret = wmKaGmvToAdDomainService.closeRule(rule.getRuleId(), operateInfo);
824	            if (ret > 0) {
825	                RuleExtraInfo ruleExtraInfo = JsonUtil.parse(rule.getExtraInfo(), RuleExtraInfo.class);
826	                if (ruleExtraInfo == null) {
827	                    String info = String.format("extraInfo is null, ruleId=%s&extraInfo=%s", rule.getRuleId(), rule.getExtraInfo());
828	                    Cat.logEvent("SDF", "PostActionFail", "1", info);
