/**
 * @ClassName ModifySdfTest
 * @Description 测试 AdAccountSdfAppService.modifySdf：CUSTOM 模式商家自助修改转入比例
 * @Author ai-coding
 * @Date 2026-05-06
 */
@RunWith(MockitoJUnitRunner.class)
public class ModifySdfTest {

    @InjectMocks
    private AdAccountSdfAppService adAccountSdfAppService;

    @Mock
    private SdfRatioConfigFutureRepository sdfRatioConfigFutureRepository;

    @Mock
    private AdAccountSdfService adAccountSdfService;

    @Mock
    private KVService kvService;

    private MockedStatic<ConfigUtilAdapter> mockedConfigUtil;

    @Before
    public void setUp() {
        ReflectionTestUtils.setField(adAccountSdfAppService, "self", adAccountSdfAppService);
        mockedConfigUtil = Mockito.mockStatic(ConfigUtilAdapter.class);
        mockedConfigUtil.when(() -> ConfigUtilAdapter.getInt(anyString(), anyInt())).thenReturn(2);
        mockedConfigUtil.when(() -> ConfigUtilAdapter.getInt(anyString())).thenReturn(2);
        mockedConfigUtil.when(() -> ConfigUtilAdapter.getString(eq("sdf_ratio_max_cash"), anyString())).thenReturn("50");
        mockedConfigUtil.when(() -> ConfigUtilAdapter.getString(anyString(), anyString())).thenAnswer(inv -> inv.getArgument(1));

        when(kvService.setnxByRedis(anyString(), anyString(), anyString(), anyInt())).thenReturn(true);
    }

    @After
    public void tearDown() {
        if (mockedConfigUtil != null) {
            mockedConfigUtil.close();
        }
    }

    private SdfAdAccountSign buildCustomSign(long activityId) {
        SdfAdAccountSign sign = new SdfAdAccountSign();
        sign.setId(100L);
        sign.setPartnerId(5001L);
        sign.setPartnerType(1);
        sign.setActivityId(activityId);
        sign.setRatioMode(SdfRatioModeEnum.CUSTOM.getMode());
        sign.setStatus(SdfAdAccountSignStatusEnum.EFFECTIVE.getStatus());
        sign.setCashCycleStartDate(20260101);
        sign.setCashCycleEndDate(20991231);
        return sign;
    }

    private SdfAdAccountActivity buildActivity(long id, BigDecimal cashRatioDecimal, BigDecimal ratioVariable) {
        SdfAdAccountActivity activity = new SdfAdAccountActivity();
        activity.setId(id);
        activity.setActivityId(id);
        activity.setCashRatioDecimal(cashRatioDecimal);
        activity.setRatioVariable(ratioVariable);
        activity.setRatioMode(SdfRatioModeEnum.CUSTOM.getMode());
        return activity;
    }

    private SdfModifyReq buildReq(long partnerId, int partnerType, String cashRatio) {
        SdfModifyReq req = new SdfModifyReq();
        req.setPartnerId(partnerId);
        req.setPartnerType(partnerType);
        req.setCashRatio(cashRatio);
        req.setOperator("test_mis");
        return req;
    }

    // ── Test 1: non-CUSTOM mode → BusinessRuntimeException ──────────────────

    @Test(expected = BusinessRuntimeException.class)
    public void nonCustomMode_throwsBusinessRuntimeException() {
        SdfAdAccountSign sign = buildCustomSign(200L);
        sign.setRatioMode(SdfRatioModeEnum.FIXED.getMode());
        when(adAccountSdfService.getAccountLastSdfSign(5001L, 1)).thenReturn(sign);

        adAccountSdfAppService.modifySdf(buildReq(5001L, 1, "0.09"));
    }

    // ── Test 2: not signed → BusinessRuntimeException ───────────────────────

    @Test(expected = BusinessRuntimeException.class)
    public void notSigned_throwsBusinessRuntimeException() {
        when(adAccountSdfService.getAccountLastSdfSign(5001L, 1)).thenReturn(null);

        adAccountSdfAppService.modifySdf(buildReq(5001L, 1, "0.09"));
    }

    // ── Test 3: cashRatio exceeds max → BusinessRuntimeException ─────────────

    @Test(expected = BusinessRuntimeException.class)
    public void cashRatioExceedsMax_throwsBusinessRuntimeException() {
        long activityId = 201L;
        SdfAdAccountSign sign = buildCustomSign(activityId);
        when(adAccountSdfService.getAccountLastSdfSign(5001L, 1)).thenReturn(sign);

        SdfAdAccountActivity activity = buildActivity(activityId, new BigDecimal("10"), new BigDecimal("3"));
        when(adAccountSdfService.getActivityByPartnerAndActivityId(5001L, 1, activityId)).thenReturn(activity);

        // max is 50(%); pass 60(%) → exceeds max
        adAccountSdfAppService.modifySdf(buildReq(5001L, 1, "60"));
    }

    // ── Test 4: cashRatio below min → BusinessRuntimeException ───────────────

    @Test(expected = BusinessRuntimeException.class)
    public void cashRatioBelowMin_throwsBusinessRuntimeException() {
        long activityId = 202L;
        SdfAdAccountSign sign = buildCustomSign(activityId);
        when(adAccountSdfService.getAccountLastSdfSign(5001L, 1)).thenReturn(sign);

        // cashRatioDecimal=10(%), ratioVariable=3(%) → min=max(1, 7)=7
        SdfAdAccountActivity activity = buildActivity(activityId, new BigDecimal("10"), new BigDecimal("3"));
        when(adAccountSdfService.getActivityByPartnerAndActivityId(5001L, 1, activityId)).thenReturn(activity);

        // pass 6(%) → below min
        adAccountSdfAppService.modifySdf(buildReq(5001L, 1, "6"));
    }

    // ── Test 5: valid ratio → inserts pending record ──────────────────────────

    @Test
    public void validRatio_insertsPendingRecord() {
        long activityId = 203L;
        SdfAdAccountSign sign = buildCustomSign(activityId);
        when(adAccountSdfService.getAccountLastSdfSign(5001L, 1)).thenReturn(sign);

        // cashRatioDecimal=10(%), ratioVariable=3(%) → min=max(1, 7)=7, max=50(%)
        SdfAdAccountActivity activity = buildActivity(activityId, new BigDecimal("10"), new BigDecimal("3"));
        when(adAccountSdfService.getActivityByPartnerAndActivityId(5001L, 1, activityId)).thenReturn(activity);

        adAccountSdfAppService.modifySdf(buildReq(5001L, 1, "9"));

        ArgumentCaptor<List> captor = ArgumentCaptor.forClass(List.class);
        verify(sdfRatioConfigFutureRepository).batchInsert(captor.capture());

        List<WmAdSdfRatioConfigFuture> inserted = captor.getValue();
        assertEquals(1, inserted.size());
        WmAdSdfRatioConfigFuture record = inserted.get(0);

        assertEquals(activityId, record.getActivityId());
        assertEquals(5001L, record.getPartnerId());
        assertEquals(1, record.getPartnerType());
        assertEquals(0, new BigDecimal("9").compareTo(record.getCashRatio()));
        assertEquals(WmAdSdfRatioConfigFuture.SOURCE_MERCHANT_SELF, record.getSource());
        assertEquals(WmAdSdfRatioConfigFuture.STATUS_PENDING, record.getStatus());
        assertEquals("test_mis", record.getOperator());
        assertTrue("effectiveDate should be tomorrow (> today)", record.getEffectiveDate() > 20260506);
    }
