public Pair<SdfAccountActivityInfo, SdfAdAccountSign> getSdfSignInfo(long partnerId, int partnerType) {
    // 1. 获取商家最新的签约记录
    SdfAdAccountSign adAccountSdfSign = adAccountSdfService.getAccountLastSdfSign(partnerId, partnerType);
    int date = DateTimeUtil.getToday();

    // 2. 检查协议是否过期，如果过期则自动解约
    if (adAccountSdfSign != null 
            && SdfAdAccountSignStatusEnum.isEffective(adAccountSdfSign.getStatus())
            && adAccountSdfSign.getCashCycleEndDate() < date) {
        terminateSdfSign(adAccountSdfSign, SdfAdAccountSignOperateTypeEnum.SYSTEM_TERMINATE.getType(), null);
    }

    // 3. 获取活动信息（已签约用签约活动，未签约用当前可参加活动）
    SdfAdAccountActivity adAccountSdfActivity;
    if (!isSign(adAccountSdfSign)) {
        adAccountSdfActivity = adAccountSdfService.getActivityByPartnerAndDate(partnerId, partnerType, date);
    } else {
        adAccountSdfActivity = adAccountSdfService.getActivityByPartnerAndActivityId(partnerId, partnerType, adAccountSdfSign.getActivityId());
    }

    SdfAccountActivityInfo activityInfo = convertToSdfAccountActivityInfo(adAccountSdfActivity, partnerId);
    return Pair.of(activityInfo, adAccountSdfSign);
}
```

### 方法 2: getRatioInfo（第2074-2143行）- 获取当前生效的转入比例

```java
public SdfRatioInfoDTO getRatioInfo(long partnerId, int partnerType, SdfAdAccountSign preloadedSign) {
    // 1. 获取签约记录
    SdfAdAccountSign sign = preloadedSign != null 
        ? preloadedSign 
        : adAccountSdfService.getAccountLastSdfSign(partnerId, partnerType);
    int today = DateTimeUtil.getToday();

    // 2. 获取活动记录（根据是否已签约选择不同的查询方式）
    SdfAdAccountActivity activity;
    Integer ratioMode;
    if (isSign(sign)) {
        activity = adAccountSdfService.getActivityByPartnerAndActivityId(partnerId, partnerType, sign.getActivityId());
        ratioMode = sign.getRatioMode();
    } else {
        activity = adAccountSdfService.getActivityByPartnerAndDate(partnerId, partnerType, today);
        ratioMode = activity != null ? activity.getRatioMode() : null;
    }

    if (activity == null) {
        return null;
    }

    // 3. 对于固定模式，直接返回活动的基础比例
    SdfRatioModeEnum mode = SdfRatioModeEnum.fromDb(ratioMode);
    if (mode == SdfRatioModeEnum.FIXED) {
        return buildSdfRatioInfoDTO(activity, sign, null);
    }

    // 4. 对于动态/自定义模式，需要查询待生效的比例配置
    long activityId = activity.getActivityId();
    List<WmAdSdfRatioConfigFuture> pendingList = 
        sdfRatioConfigFutureRepository.selectLatestPendingByPartners(
            activityId, 
            Collections.singletonList(new PartnerKey(partnerId, partnerType))
        );
    WmAdSdfRatioConfigFuture pendingConfig = pendingList.isEmpty() ? null : pendingList.get(0);

    return buildSdfRatioInfoDTO(activity, sign, pendingConfig);
}

private SdfRatioInfoDTO buildSdfRatioInfoDTO(SdfAdAccountActivity activity,
                                              SdfAdAccountSign sign,
                                              WmAdSdfRatioConfigFuture pendingConfig) {
    Integer ratioMode = sign != null && isSign(sign) ? sign.getRatioMode() : activity.getRatioMode();
    SdfRatioModeEnum mode = SdfRatioModeEnum.fromDb(ratioMode);

    SdfRatioInfoDTO dto = new SdfRatioInfoDTO();
    dto.setRatioMode(mode.getMode());

    String pendingCashRatio = pendingConfig != null ? pendingConfig.getCashRatio().toPlainString() : null;

    if (mode == SdfRatioModeEnum.FIXED) {
        // 固定模式：比例固定为活动基础比例
        dto.setCurrentCashRatio(activity.getCashRatioDecimal().toPlainString());
    } else if (mode == SdfRatioModeEnum.DYNAMIC) {
        // 动态模式：当前比例为活动基础比例
        dto.setCurrentCashRatio(activity.getCashRatioDecimal().toPlainString());
        dto.setPendingCashRatio(pendingCashRatio);  // 明天生效的比例

        // 获取比例浮动范围
        SdfRatioBounds bounds = resolveRatioBounds(activity);
        dto.setRatioMin(bounds.min.stripTrailingZeros().toPlainString());
        dto.setRatioMax(bounds.max.stripTrailingZeros().toPlainString());
    } else if (mode == SdfRatioModeEnum.CUSTOM) {
        // 自定义模式：当前比例为签约记录中的自定义比例
        BigDecimal currentRatio = (sign != null && isSign(sign))
                ? sign.getCashRatioDecimal()
                : activity.getCashRatioDecimal();
        dto.setCurrentCashRatio(currentRatio.toPlainString());
        dto.setPendingCashRatio(pendingCashRatio);  // 明天生效的比例

        dto.setRatioMin(resolveRatioMin(activity).toPlainString());
        dto.setRatioMax(resolveConfigCap().toPlainString());
    }

    return dto;
}
```

